// ══════════════════════════════════════════
// CONFIG — cole seus dados aqui
const IG_USER_ID = 'SEU_IG_USER_ID_AQUI';   // ex: 17841401915115561
const IG_TOKEN   = 'SEU_TOKEN_AQUI';         // token do Graph API Explorer
// ══════════════════════════════════════════

const body    = $input.first().json.body || $input.first().json;
const urls    = body.urls    || [];
const caption = body.caption || '';
const BASE    = 'https://graph.facebook.com/v19.0';

if (!urls.length) throw new Error('Nenhuma URL de imagem recebida');
if (urls.length > 10) throw new Error('Instagram aceita máximo 10 imagens por carrossel');

// Helper: POST com query params
const igPost = async (path, params) => {
  const url = new URL(BASE + path);
  Object.entries({ ...params, access_token: IG_TOKEN })
    .forEach(([k, v]) => url.searchParams.set(k, String(v)));
  const r = await fetch(url.toString(), { method: 'POST' });
  const data = await r.json();
  if (data.error) throw new Error(`[Meta] ${data.error.message} (code ${data.error.code})`);
  return data;
};

// 1. Criar item de mídia para cada imagem
const itemIds = [];
for (const imageUrl of urls) {
  const item = await igPost(`/${IG_USER_ID}/media`, {
    image_url: imageUrl,
    is_carousel_item: 'true'
  });
  itemIds.push(item.id);
}

// 2. Criar container do carrossel
const carousel = await igPost(`/${IG_USER_ID}/media`, {
  media_type: 'CAROUSEL',
  children:   itemIds.join(','),
  caption
});

// 3. Publicar
const pub = await igPost(`/${IG_USER_ID}/media_publish`, {
  creation_id: carousel.id
});

return [{ json: { ok: true, postId: pub.id, slides: urls.length } }];
